def fingerprint_technologies(headers, html):
    techs = []

    # Check HTTP headers
    server = headers.get('Server', '')
    if server: techs.append(('Server', server, 'HTTP Header'))
    powered = headers.get('X-Powered-By', '')
    if powered: techs.append(('Backend', powered, 'HTTP Header'))

    # Check cookies
    cookies = headers.get('Set-Cookie', '')
    if 'PHPSESSID' in cookies: techs.append(('Language', 'PHP', 'Cookie'))
    if 'JSESSIONID' in cookies: techs.append(('Language', 'Java', 'Cookie'))
