    gen = soup.find('meta', attrs={'name': 'generator'})
    if gen: techs.append(('CMS', gen.get('content', ''), 'Meta Tag'))

    if 'wp-content' in html: techs.append(('CMS', 'WordPress', 'HTML Pattern'))
    if 'drupal' in html.lower(): techs.append(('CMS', 'Drupal', 'HTML Pattern'))
    if 'jquery' in html.lower(): techs.append(('JS Library', 'jQuery', 'Script'))
    if 'react' in html.lower(): techs.append(('JS Framework', 'React', 'Script'))
