import re
def find_secrets(html):
    patterns = [
        (r'AIza[0-9A-Za-z_-]{35}', 'Google API Key'),
        (r'sk_live_[0-9a-zA-Z]{20,}', 'Stripe Secret Key'),
        (r'AKIA[0-9A-Z]{16}', 'AWS Access Key'),
    ]
    results = []
    for pat, desc in patterns:
        for m in re.findall(pat, html):
            results.append((desc, m, 'HIGH'))
    var_pat = r'(?:var|let|const)\s+(\w*(?:key|secret|token|pass)\w*)\s*=\s*["\']([^"\']+)["\']'
    for name, val in re.findall(var_pat, html, re.IGNORECASE):
        if (name, val, 'HIGH') not in results:
            results.append((name, val, 'HIGH'))
    return results

def deduplicate(items):
    seen = set()
    result = []
    for item in items:
        if item not in seen:
            seen.add(item)
            result.append(item)
    return result

def score_findings(findings):
    risk_map = {'api_key':'CRITICAL','debug':'HIGH','path':'HIGH','version':'MEDIUM','subdomain':'MEDIUM','email':'LOW'}
    order = {'CRITICAL':0,'HIGH':1,'MEDIUM':2,'LOW':3}
    scored = [(t, v, risk_map.get(t, 'LOW')) for t, v in findings]
    return sorted(scored, key=lambda x: order.get(x[2], 4))

def generate_html_report(target, findings, output_path):
    colors = {'Critical':'red','High':'orange','Medium':'yellow','Low':'green'}
    rows = ''
    for f in findings:
        c = colors.get(f['risk'], 'white')
        rows += f'<tr><td>{f["type"]}</td><td>{f["value"]}</td><td style="color:{c}">{f["risk"]}</td></tr>\n'
    html = f'<html><head><title>OSINT: {target}</title></head><body>\n<h1>OSINT Report: {target}</h1>\n<table border="1"><tr><th>Type</th><th>Value</th><th>Risk</th></tr>\n{rows}</table></body></html>'
    with open(output_path, 'w') as f: f.write(html)
    import os
    print(f'HTML report saved to {output_path} ({os.path.getsize(output_path)} bytes)')

