def compare_scans(scan1, scan2):
    all_cats = set(scan1.keys()) | set(scan2.keys())
    for cat in sorted(all_cats):
        s1 = scan1.get(cat, set())
        s2 = scan2.get(cat, set())
        print(f'{cat}:')
        for item in sorted(s2 - s1): print(f'  New: {item}')
        for item in sorted(s1 - s2): print(f'  Removed: {item}')
        for item in sorted(s1 & s2): print(f'  Unchanged: {item}')
